history.content:
There is a miscompilation issue report in InstCombine: 

https://alive2.llvm.org/ce/z/c__jy8

this function:
```llvm
define i32 @f(i32 %0) {
  %2 = sub nuw i32 -2, %0
  %3 = tail call i32 @llvm.ctlz.i32(i32 %2, i1 false)
  %4 = sub i32 32, %3
  %5 = shl i32 1, %4
  %6 = icmp ult i32 %0, -2
  %7 = select i1 %6, i32 %5, i32 1
  ret i32 %7
}

; Function Attrs: nocallback nofree nosync nounwind speculatable willreturn memory(none)
declare i32 @llvm.ctlz.i32(i32, i1 immarg) #0

attributes #0 = { nocallback nofree nosync nounwind speculatable willreturn memory(none) }
```

is getting rewritten to not have the select, but the select was blocking a poison value. the bad thing happens when -1 is passed as an argument, see the Alive link for a detailed execution trace

```llvm
define i32 @f(i32 %0) {
  %2 = sub nuw i32 -2, %0
  %3 = tail call range(i32 0, 33) i32 @llvm.ctlz.i32(i32 %2, i1 false)
  %4 = sub nsw i32 0, %3
  %5 = and i32 %4, 31
  %6 = shl nuw i32 1, %5
  ret i32 %6
}

; Function Attrs: nocallback nofree nosync nounwind speculatable willreturn memory(none)
declare i32 @llvm.ctlz.i32(i32, i1 immarg) #0

attributes #0 = { nocallback nofree nosync nounwind speculatable willreturn memory(none) }
```

cc @nunoplopes 

The maintainers proposed the following patch to fix the issue:

commit b5f4210e9f51f938ae517f219f04f9ab431a2684
Author: Yingwei Zheng <dtcxzyw2333@gmail.com>
Date:   Mon May 13 14:27:59 2024 +0800

    [InstCombine] Drop nuw flag when CtlzOp is a sub nuw (#91776)

    See the following case:
    ```
    define i32 @src1(i32 %x) {
      %dec = sub nuw i32 -2, %x
      %ctlz = tail call i32 @llvm.ctlz.i32(i32 %dec, i1 false)
      %sub = sub nsw i32 32, %ctlz
      %shl = shl i32 1, %sub
      %ugt = icmp ult i32 %x, -2
      %sel = select i1 %ugt, i32 %shl, i32 1
      ret i32 %sel
    }

    define i32 @tgt1(i32 %x) {
      %dec = sub nuw i32 -2, %x
      %ctlz = tail call i32 @llvm.ctlz.i32(i32 %dec, i1 false)
      %sub = sub nsw i32 32, %ctlz
      %and = and i32 %sub, 31
      %shl = shl nuw i32 1, %and
      ret i32 %shl
    }
    ```
    `nuw` in `%dec` should be dropped after the select instruction is
    eliminated.

    Alive2: https://alive2.llvm.org/ce/z/7S9529

    Fixes https://github.com/llvm/llvm-project/issues/91691.

